const ordersByBuyerEmail = {};
for (const order of orders) {
  ordersByBuyerEmail[order.buyer.contact.email.trim().toLowerCase()] = order;
}

const productsByCategorySku = {};
for (const product of products) {
  productsByCategorySku[`${product.category.slug}:${product.sku.trim().toLowerCase()}`] = product;
}

const postsByAuthorSlug = {};
for (const post of posts) {
  postsByAuthorSlug[`${post.author.handle.trim().toLowerCase()}:${post.slug}`] = post;
}

const devicesByTenantToken = {};
for (const device of devices) {
  devicesByTenantToken[`${device.tenant.id}:${device.auth.token.trim().toLowerCase()}`] = device;
}

const ticketsByOwnerRegion = {};
for (const ticket of tickets) {
  ticketsByOwnerRegion[`${ticket.owner.email.trim().toLowerCase()}:${ticket.region.code}`] = ticket;
}

const accountsByOrgHandle = {};
for (const account of accounts) {
  accountsByOrgHandle[`${account.org.slug}:${account.profile.handle.trim().toLowerCase()}`] = account;
}
